// Get PAC data by senator name
export function getSenatorPACData(senatorName: string): SenatorPACData | null {
  const fecId = senatorNameToId[senatorName];
  
  if (!fecId || !pacDataById[fecId]) {
    // Return sample data if not found
    return {
      pacs: [
        { name: "No data available", amount: 0, color: "#95A5A6" }
      ],
      individuals: { small: 0, large: 0 },
      totalPAC: 0,
      totalIndividual: 0
    };
  }
  
  const pacs = pacDataById[fecId];
  const totalPAC = pacs.reduce((sum, pac) => sum + pac.amount, 0);
  
  // TODO: Add individual contribution data
  // For now, using placeholder values
  const individuals = {
    small: Math.floor(totalPAC * 0.3),  // Estimate: 30% from small donors
    large: Math.floor(totalPAC * 0.7)   // Estimate: 70% from large donors
  };
  
  return {
    pacs,
    individuals,
    totalPAC,
    totalIndividual: individuals.small + individuals.large
  };
}

// Get all senator names that have PAC data
export function getSenatorsWithPACData(): string[] {
  return Object.keys(senatorNameToId);
}
